// Verify Quo (formerly OpenPhone) webhook signatures — supports both schemes.
// Scheme A (current): "openphone-signature: hmac;1;<unix-ms>;<base64>" over "<ts>.<minified JSON body>"
// Scheme B (beta, Svix-style): webhook-id / webhook-timestamp / webhook-signature over "<id>.<unix-s>.<raw body>"
// Fails CLOSED: any parse/decode problem rejects the delivery.
const crypto = require('crypto');

const item = $input.first();
const headers = item.json.headers || {};

// Raw body — the Webhook node must have "Raw Body" enabled.
let raw = null;
if (item.binary && item.binary.data) {
  raw = (await this.helpers.getBinaryDataBuffer(0, 'data')).toString('utf8');
} else if (typeof item.json.body === 'string') {
  raw = item.json.body;
} else if (item.json.body && typeof item.json.body === 'object') {
  // Fallback if Raw Body was left off. Scheme A re-serializes anyway; Scheme B needs true raw bytes.
  raw = JSON.stringify(item.json.body);
}
if (!raw) throw new Error('verify: missing request body');

if (($env.ALLOW_UNSIGNED || '0') === '1') {
  console.warn('verify: ALLOW_UNSIGNED=1 — signature check SKIPPED (local testing only)');
  return [{ json: { body: JSON.parse(raw) } }];
}

const secrets = ($env.QUO_WEBHOOK_SECRET || '').split(',').map(function (s) { return s.trim(); }).filter(Boolean);
if (secrets.length === 0) {
  throw new Error('verify: QUO_WEBHOOK_SECRET is not set (or set ALLOW_UNSIGNED=1 for local tests only)');
}

const skewSeconds = Number($env.SIGNATURE_SKEW_SECONDS) > 0 ? Number($env.SIGNATURE_SKEW_SECONDS) : 300;
const skewMs = skewSeconds * 1000;
const nowMs = Date.now();

function safeEqual(aB64, bB64) {
  try {
    const a = Buffer.from(String(aB64));
    const b = Buffer.from(String(bB64));
    if (a.length !== b.length) return false;
    return crypto.timingSafeEqual(a, b);
  } catch (e) {
    return false;
  }
}

let ok = false;

const sigHeader = headers['openphone-signature'];
if (sigHeader) {
  // --- Scheme A ---
  const parts = String(sigHeader).split(';');
  if (parts.length === 4 && parts[0] === 'hmac' && parts[1] === '1') {
    const ts = Number(parts[2]);
    if (Number.isFinite(ts) && Math.abs(nowMs - ts) <= skewMs) {
      let canonical = null;
      try { canonical = JSON.stringify(JSON.parse(raw)); } catch (e) { canonical = null; }
      if (canonical !== null) {
        const signed = parts[2] + '.' + canonical;
        for (const secret of secrets) {
          if (secret.startsWith('whsec_')) continue;
          try {
            const digest = crypto.createHmac('sha256', Buffer.from(secret, 'base64')).update(signed, 'utf8').digest('base64');
            if (safeEqual(digest, parts[3])) { ok = true; break; }
          } catch (e) { /* fail closed */ }
        }
      }
    }
  }
} else if (headers['webhook-id'] && headers['webhook-timestamp'] && headers['webhook-signature']) {
  // --- Scheme B ---
  const tsSec = Number(headers['webhook-timestamp']);
  if (Number.isFinite(tsSec) && Math.abs(nowMs - tsSec * 1000) <= skewMs) {
    const signed = headers['webhook-id'] + '.' + headers['webhook-timestamp'] + '.' + raw;
    const candidates = String(headers['webhook-signature'])
      .split(' ')
      .map(function (p) { return p.split(',')[1]; })
      .filter(Boolean);
    for (const secret of secrets) {
      if (!secret.startsWith('whsec_')) continue;
      try {
        const digest = crypto.createHmac('sha256', Buffer.from(secret.slice(6), 'base64')).update(signed, 'utf8').digest('base64');
        if (candidates.some(function (c) { return safeEqual(digest, c); })) { ok = true; break; }
      } catch (e) { /* fail closed */ }
    }
  }
}

if (!ok) throw new Error('verify: webhook signature rejected (forged, replayed, or misconfigured secret)');

return [{ json: { body: JSON.parse(raw) } }];

// Guards + flatten. Cheap checks first — nothing reaches the LLM unless it is worth the spend.
const body = $json.body || {};
const data = body.data || {};
// Tolerant extraction: the transcript object may live at body.data.object, body.data, or the body root.
let obj = body;
if (data && typeof data === 'object') {
  if (data.object && typeof data.object === 'object') obj = data.object;
  else if (data.callId || data.dialogue) obj = data;
}

const callId = obj.callId || obj.id || null;
const status = obj.status || 'completed';
const duration = Math.round(Number(obj.duration || 0));
const dialogue = Array.isArray(obj.dialogue) ? obj.dialogue : null;

if (!callId) return [{ json: { skip: 'no_call_id' } }];
if (status !== 'completed') return [{ json: { skip: 'transcript_status_' + status } }];
if (!dialogue || dialogue.length === 0) return [{ json: { skip: 'empty_transcript' } }];

const minSeconds = Number.isFinite(Number($env.MIN_CALL_SECONDS)) && $env.MIN_CALL_SECONDS !== undefined
  ? Number($env.MIN_CALL_SECONDS) : 30;
if (duration < minSeconds) return [{ json: { skip: 'too_short' } }];

// Dedupe across redeliveries. NOTE: workflow static data persists only for ACTIVE
// (production) executions — manual test runs always start empty.
const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.seenCallIds)) staticData.seenCallIds = [];
if (staticData.seenCallIds.indexOf(callId) !== -1) return [{ json: { skip: 'duplicate' } }];
staticData.seenCallIds.push(callId);
while (staticData.seenCallIds.length > 1000) staticData.seenCallIds.shift();

// OWNED_NUMBERS fallback map, e.g. "+15555550100=Alex Agent,+15555550101=Bailey Agent".
// Matching external identifiers are forced to AGENT (forwarded-line edge case).
const owned = new Set();
for (const pair of ($env.OWNED_NUMBERS || '').split(',')) {
  const num = pair.split('=')[0].trim();
  if (num) owned.add(num);
}

// Speaker identity comes from userId / E.164 identifiers ONLY — never from spoken content.
const CONTROL = /[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F\u200B-\u200F\u2028\u2029\uFEFF]/g;
const lines = [];
for (const turn of dialogue) {
  if (!turn || typeof turn.content !== 'string') continue;
  const content = turn.content.replace(CONTROL, ' ').replace(/\s+/g, ' ').trim();
  if (!content) continue;
  const isAgent = (turn.userId !== null && turn.userId !== undefined && turn.userId !== '') || owned.has(turn.identifier || '');
  lines.push((isAgent ? 'AGENT: ' : 'CALLER: ') + content);
}
let transcriptFlat = lines.join('\n');
if (!transcriptFlat) return [{ json: { skip: 'empty_transcript' } }];

// Cap: head 60% + tail 40% (openings carry context; commitments cluster at the close).
const maxChars = Number.isFinite(Number($env.MAX_TRANSCRIPT_CHARS)) && $env.MAX_TRANSCRIPT_CHARS !== undefined
  ? Number($env.MAX_TRANSCRIPT_CHARS) : 24000;
if (transcriptFlat.length > maxChars) {
  const head = Math.floor(maxChars * 0.6);
  const tail = Math.floor(maxChars * 0.4);
  transcriptFlat = transcriptFlat.slice(0, head) + '\n[... middle trimmed ...]\n' + transcriptFlat.slice(transcriptFlat.length - tail);
}

const callDateIso = obj.createdAt || body.createdAt || new Date().toISOString();
const direction = obj.direction || 'unknown';

return [{ json: { callId: callId, transcriptFlat: transcriptFlat, callDateIso: callDateIso, direction: direction, duration: duration } }];

// Layer-2 deterministic validation. Model output is NEVER trusted:
// schema coercion, enum whitelist, groundedness check, due-date window,
// caps, exfil scrub, injection lint. Runs on every response, no exceptions.
const ctx = $('Guards + Flatten').first().json;

let rawText = '';
try { rawText = $json.choices[0].message.content || ''; } catch (e) { rawText = ''; }

// Tolerant parse: strip code fences, slice the outermost {...}.
let text = String(rawText).trim();
const fence = text.match(/\`\`\`(?:json)?\s*([\s\S]*?)\`\`\`/i);
if (fence) text = fence[1].trim();
const firstBrace = text.indexOf('{');
const lastBrace = text.lastIndexOf('}');
if (firstBrace === -1 || lastBrace <= firstBrace) throw new Error('validate: model returned no JSON object');
let parsed;
try { parsed = JSON.parse(text.slice(firstBrace, lastBrace + 1)); } catch (e) { throw new Error('validate: model returned invalid JSON'); }

const includeCaller = ($env.INCLUDE_CALLER_COMMITMENTS || '0') === '1';
const minConfRaw = String($env.MIN_CONFIDENCE || 'medium').toLowerCase();
const confRank = { low: 0, medium: 1, high: 2 };
const minConfidence = confRank[minConfRaw] !== undefined ? minConfRaw : 'medium';
let maxTasks = Number.isFinite(Number($env.MAX_TASKS_PER_CALL)) && $env.MAX_TASKS_PER_CALL !== undefined
  ? Number($env.MAX_TASKS_PER_CALL) : 8;
maxTasks = Math.min(Math.max(1, maxTasks), 8); // hard ceiling 8 — env may lower it, never raise it

function asStr(v) { return typeof v === 'string' ? v : ''; }
function asNullableStr(v) { return typeof v === 'string' && v.trim() ? v : null; }

function normalize(s) {
  return String(s).toLowerCase().replace(/[^\p{L}\p{N}\s]/gu, ' ').replace(/\s+/g, ' ').trim();
}
const normalizedTranscript = normalize(ctx.transcriptFlat);

const CONTROL = /[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F\u200B-\u200F\u2028\u2029\uFEFF]/g;
function sanitizeForTask(s) {
  return String(s)
    .replace(CONTROL, ' ')
    .replace(/\[([^\]]*)\]\(([^)]*)\)/g, '$1')
    .replace(/https?:\/\/\S+/gi, '[removed]')
    .replace(/www\.\S+/gi, '[removed]')
    .replace(/[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}/g, '[removed]')
    .replace(/\+?\d[\d\s().-]{7,}\d/g, '[removed]')
    .replace(/\s+/g, ' ')
    .trim();
}

const INJECTION = [
  /ignore (all|previous|prior)/i,
  /system prompt/i,
  /api[._-]?key/i,
  /api\.openphone/i,
  /webhook/i,
  /curl /i,
  /<script/i,
];
function lintSentences(s) {
  const sentences = String(s).split(/(?<=[.!?])\s+/);
  return sentences.filter(function (sn) {
    return !INJECTION.some(function (rx) { return rx.test(sn); });
  }).join(' ').trim();
}

function truncate(s, max) {
  if (s.length <= max) return s;
  const cut = s.slice(0, max - 1);
  const space = cut.lastIndexOf(' ');
  return (space > max * 0.5 ? cut.slice(0, space) : cut) + '\u2026';
}

const callDateMs = Date.parse(ctx.callDateIso) || Date.now();
const windowEndMs = callDateMs + 365 * 24 * 60 * 60 * 1000;

const dropped = [];
const out = [];
const list = Array.isArray(parsed.commitments) ? parsed.commitments : [];
let n = 0;

for (const rawItem of list) {
  if (out.length >= maxTasks) { dropped.push({ reason: 'cap' }); continue; }
  if (!rawItem || typeof rawItem !== 'object') { dropped.push({ reason: 'not_object' }); continue; }

  const who = asStr(rawItem.who).toLowerCase();
  const confidence = asStr(rawItem.confidence).toLowerCase();
  if (who !== 'agent' && who !== 'caller') { dropped.push({ reason: 'bad_who' }); continue; }
  if (confRank[confidence] === undefined) { dropped.push({ reason: 'bad_confidence' }); continue; }
  if (who === 'caller' && !includeCaller) { dropped.push({ reason: 'caller_excluded' }); continue; }
  if (confRank[confidence] < confRank[minConfidence]) { dropped.push({ reason: 'low_confidence' }); continue; }

  // Groundedness: the quote must actually appear in the transcript (normalized substring).
  // This deterministically kills hallucinated promises AND injection-fabricated tasks.
  const quote = asStr(rawItem.verbatim_quote);
  const qNorm = normalize(quote);
  if (qNorm.length < 15 || normalizedTranscript.indexOf(qNorm) === -1) { dropped.push({ reason: 'ungrounded_quote' }); continue; }

  // Due-date sanity: parseable AND within [call_date, call_date + 365d], else drop the DATE only.
  let dueIso = asNullableStr(rawItem.due_iso);
  if (dueIso) {
    const dueMs = Date.parse(dueIso);
    if (!Number.isFinite(dueMs) || dueMs < callDateMs || dueMs > windowEndMs) dueIso = null;
  }

  let title = sanitizeForTask(rawItem.title);
  if (INJECTION.some(function (rx) { return rx.test(title); })) { dropped.push({ reason: 'injection_title' }); continue; }
  title = truncate(title, 80);
  const detail = truncate(lintSentences(sanitizeForTask(rawItem.detail)), 200);
  const quoteClean = lintSentences(sanitizeForTask(quote));
  if (!title || (!detail && !quoteClean)) { dropped.push({ reason: 'emptied_by_scrub' }); continue; }

  const dueSpoken = asNullableStr(rawItem.due_spoken) ? sanitizeForTask(rawItem.due_spoken) : 'n/a';

  n += 1;
  const description = (detail || 'See quote.')
    + '\nQuote: "' + quoteClean + '"'
    + '\nSpoken due: ' + dueSpoken
    + '\nSource: talkback ref:' + ctx.callId + '/' + n;

  const task = { title: title, description: description, activityId: ctx.callId };
  if (dueIso) task.dueDate = dueIso;
  if ($env.QUO_DEFAULT_ASSIGNEE) task.assignedTo = $env.QUO_DEFAULT_ASSIGNEE;
  out.push({ json: task });
}

console.log('TalkBack: extracted=' + list.length + ' surviving=' + out.length + ' dropped=' + JSON.stringify(dropped));

// If nothing survives, this returns no items: the run ends and n8n sends its
// default webhook response (still a 2xx — the provider will not retry).
return out;
